[SysClientCacheDataMethodAttribute(true)]
public static display str mainCommodityACF(GeneralJournalAccountEntry _this)
{
    DimensionAttributeLevelValueAllView dimAttriView;
    DimensionAttribute                  dimAttri;
    str entity;
    ETGACFParameters    acfParameters = ETGACFParameters::find();
    if(acfParameters.MainCommodity == '')
    {
        return '';
    }

    select DisplayValue from dimAttriView
        where dimAttriView.ValueCombinationRecId == _this.LedgerDimension
        join BackingEntityType from dimAttri
        where dimAttri.RecId == dimAttriView.DimensionAttribute
        && dimAttri.Name == acfParameters.MainCommodity;//"Entity";

    if(dimAttriView)
    {
        entity = dimAttriView.DisplayValue;
    }
    return entity;
}

